import React from 'react';
import { Card, CardMedia, CardContent, Typography, Button, Box, LinearProgress, Chip, useTheme, Tooltip, Badge } from '@mui/material';
import { styled, alpha } from '@mui/material/styles';
import { CalendarMonth, Person, Speed, ArrowForward, LocalOffer } from '@mui/icons-material';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';

const MotionCard = styled(motion.div)(({ theme }) => ({
  borderRadius: 20,
  overflow: 'visible',
  width: '100%',
  marginBottom: 20,
  transition: 'all 0.3s ease-in-out',
  height: '100%',
}));

const StyledCard = styled(Card)(({ theme }) => ({
  borderRadius: 20,
  overflow: 'hidden',
  height: '100%',
  display: 'flex',
  flexDirection: 'column',
  backgroundColor: theme.palette.background.paper,
  boxShadow: theme.palette.mode === 'light' 
    ? '0 10px 30px rgba(0,0,0,0.08)'
    : '0 10px 30px rgba(0,0,0,0.2)',
  transition: 'all 0.3s ease-in-out',
  '&:hover': {
    boxShadow: theme.palette.mode === 'light' 
      ? '0 15px 40px rgba(0,0,0,0.12)'
      : '0 15px 40px rgba(0,0,0,0.3)',
    transform: 'translateY(-5px)',
  }
}));

const CardDetailsContainer = styled(CardContent)(({ theme }) => ({
  padding: theme.spacing(2.5, 3, 3),
  flex: 1,
  display: 'flex',
  flexDirection: 'column',
}));

const InfoRow = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  marginRight: theme.spacing(2),
  '& svg': {
    marginRight: theme.spacing(0.7),
    fontSize: 18,
    color: theme.palette.text.secondary,
  }
}));

const BuyButton = styled(Button)(({ theme }) => ({
  borderRadius: 12,
  padding: theme.spacing(1, 2.5),
  fontWeight: 600,
  textTransform: 'none',
  boxShadow: '0 4px 12px rgba(33, 150, 243, 0.2)',
  transition: 'all 0.2s ease-in-out',
  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  '&:hover': {
    boxShadow: '0 6px 16px rgba(33, 150, 243, 0.3)',
    transform: 'translateY(-2px)',
  }
}));

const ProgressLabel = styled(Box)(({ theme }) => ({
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  width: '100%',
  marginTop: theme.spacing(0.8),
  marginBottom: theme.spacing(2.5),
}));

const PriceChip = styled(Chip)(({ theme }) => ({
  fontWeight: 700,
  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  color: 'white',
  position: 'absolute',
  top: 16,
  right: 16,
  borderRadius: 12,
  boxShadow: '0 4px 12px rgba(33, 150, 243, 0.3)',
  backdropFilter: 'blur(4px)',
  zIndex: 2,
}));

const EndingSoonBadge = styled(Box)(({ theme }) => ({
  position: 'absolute',
  top: 16,
  left: 16,
  backgroundColor: alpha(theme.palette.error.main, 0.9),
  color: 'white',
  padding: theme.spacing(0.5, 1.5),
  borderRadius: 12,
  fontWeight: 600,
  fontSize: '0.75rem',
  zIndex: 2,
  boxShadow: '0 4px 12px rgba(211, 47, 47, 0.3)',
  backdropFilter: 'blur(4px)',
}));

const CardMediaWrapper = styled(Box)(({ theme }) => ({
  position: 'relative',
  height: 200,
  overflow: 'hidden',
}));

const StyledCardMedia = styled('img')(({ theme }) => ({
  height: '100%',
  width: '100%',
  objectFit: 'cover',
  transition: 'transform 0.7s ease-in-out',
  '&:hover': {
    transform: 'scale(1.05)',
  },
}));

const DetailsButton = styled(Button)(({ theme }) => ({
  textTransform: 'none',
  fontWeight: 600,
  padding: theme.spacing(1, 2),
  borderRadius: 12,
  color: theme.palette.primary.main,
  '&:hover': {
    backgroundColor: alpha(theme.palette.primary.main, 0.08),
  }
}));

interface CarCardProps {
  id: string;
  title: string;
  image: string;
  description: string;
  ticketsSold: number;
  totalTickets: number;
  price: number;
  year: number;
  participants: number;
  endDate: string;
}

const CarCard: React.FC<CarCardProps> = ({
  id,
  title,
  image,
  description,
  ticketsSold,
  totalTickets,
  price,
  year,
  participants,
  endDate
}) => {
  const progress = (ticketsSold / totalTickets) * 100;
  const formattedPrice = new Intl.NumberFormat('ru-RU').format(price);
  const theme = useTheme();
  
  // Проверка на скорое завершение (если осталось меньше 20% билетов)
  const isEndingSoon = progress > 80;
  
  // Определяем цвет прогресс-бара в зависимости от заполнения
  const getProgressColor = () => {
    if (progress < 40) return alpha(theme.palette.primary.main, 0.9);
    if (progress < 80) return alpha(theme.palette.warning.main, 0.9);
    return alpha(theme.palette.error.main, 0.9);
  };

  return (
    <MotionCard
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4 }}
      whileHover={{ scale: 1.01 }}
    >
      <StyledCard>
        <CardMediaWrapper>
          <StyledCardMedia
            src={image}
            alt={title}
          />
          <PriceChip label={`${formattedPrice} ₽`} />
          {isEndingSoon && (
            <EndingSoonBadge>
              <Box sx={{ display: 'flex', alignItems: 'center' }}>
                <Speed fontSize="small" sx={{ mr: 0.5 }} />
                Осталось мало билетов
              </Box>
            </EndingSoonBadge>
          )}
        </CardMediaWrapper>
        
        <CardDetailsContainer>
          <Typography 
            gutterBottom 
            variant="h6" 
            component="div" 
            sx={{ 
              fontWeight: 700, 
              mb: 1,
              display: '-webkit-box',
              overflow: 'hidden',
              WebkitBoxOrient: 'vertical',
              WebkitLineClamp: 1,
            }}
          >
            {title}
          </Typography>
          
          <Typography 
            variant="body2" 
            color="text.secondary" 
            sx={{ 
              mb: 2,
              display: '-webkit-box',
              overflow: 'hidden',
              WebkitBoxOrient: 'vertical',
              WebkitLineClamp: 2,
              lineHeight: 1.5,
              flexGrow: 1
            }}
          >
            {description}
          </Typography>
          
          <Box sx={{ mt: 'auto' }}>
            <Box sx={{ display: 'flex', flexWrap: 'wrap', mb: 2 }}>
              <InfoRow>
                <CalendarMonth fontSize="small" />
                <Typography variant="body2" color="text.secondary">
                  {year} год
                </Typography>
              </InfoRow>
              
              <InfoRow>
                <Person fontSize="small" />
                <Typography variant="body2" color="text.secondary">
                  {participants} участников
                </Typography>
              </InfoRow>
            </Box>
            
            <Box>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Typography variant="caption" color="text.secondary" fontWeight={500}>
                  Продано {ticketsSold} из {totalTickets}
                </Typography>
                <Typography variant="caption" color="text.secondary" fontWeight={600}>
                  {progress.toFixed(0)}%
                </Typography>
              </Box>
              <LinearProgress 
                variant="determinate" 
                value={progress} 
                sx={{ 
                  height: 8, 
                  borderRadius: 4, 
                  mt: 0.7,
                  backgroundColor: alpha(theme.palette.primary.main, 0.15),
                  '& .MuiLinearProgress-bar': {
                    borderRadius: 4,
                    background: `linear-gradient(90deg, ${getProgressColor()} 0%, ${getProgressColor()} 100%)`,
                  }
                }} 
              />
              <ProgressLabel>
                <Typography 
                  variant="body2" 
                  color="text.secondary"
                  sx={{ 
                    display: 'flex', 
                    alignItems: 'center',
                    fontWeight: 500,
                    '& svg': { 
                      fontSize: 16, 
                      mr: 0.5, 
                      color: isEndingSoon ? theme.palette.error.main : theme.palette.text.secondary 
                    }
                  }}
                >
                  <CalendarMonth fontSize="small" />
                  До {endDate}
                </Typography>
              </ProgressLabel>
            </Box>
            
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mt: 0.5 }}>
              <Link to={`/raffles/${id}`} style={{ textDecoration: 'none' }}>
                <DetailsButton 
                  endIcon={<ArrowForward />}
                  size="small"
                >
                  Подробнее
                </DetailsButton>
              </Link>
              
              <motion.div whileTap={{ scale: 0.95 }}>
                <BuyButton 
                  variant="contained" 
                  size="medium" 
                  color="primary"
                  startIcon={<LocalOffer fontSize="small" />}
                >
                  Купить билет
                </BuyButton>
              </motion.div>
            </Box>
          </Box>
        </CardDetailsContainer>
      </StyledCard>
    </MotionCard>
  );
};

export default CarCard;
